// src/context/AppContext.js
import React, { createContext, useContext, useState, useCallback } from 'react';
import { initialStaff, initialTimetable, DAYS, PERIOD_TIMES } from '../data/initialData';

const AppContext = createContext();

export function AppProvider({ children }) {
  const [staff, setStaff] = useState(initialStaff);
  const [timetable, setTimetable] = useState(initialTimetable);
  const [leaveRequests, setLeaveRequests] = useState([
    {
      id: 1,
      teacherId: 2,
      teacherName: "Prof. Rahul Patil",
      fromDate: "2025-03-10",
      toDate: "2025-03-10",
      reason: "Medical appointment",
      status: "pending",
      substituteRequests: [],
      createdAt: "2025-03-08",
    }
  ]);
  const [notifications, setNotifications] = useState([]);

  // Find free teachers for a given day/period (not busy in timetable on that day)
  const findFreeTeachers = useCallback((day, period, excludeTeacherId) => {
    const busyTeacherIds = new Set();
    Object.entries(timetable).forEach(([teacherId, slots]) => {
      if (parseInt(teacherId) === excludeTeacherId) return;
      slots.forEach(slot => {
        if (slot.day === day && slot.period === period) {
          busyTeacherIds.add(parseInt(teacherId));
        }
      });
    });
    return staff.filter(t => t.id !== excludeTeacherId && !busyTeacherIds.has(t.id));
  }, [timetable, staff]);

  // Get timetable slots for a teacher on leave dates
  const getTeacherSlots = useCallback((teacherId, fromDate, toDate) => {
    const slots = timetable[teacherId] || [];
    const affectedSlots = [];
    const start = new Date(fromDate);
    const end = new Date(toDate);
    for (let d = new Date(start); d <= end; d.setDate(d.getDate() + 1)) {
      const dayName = DAYS[d.getDay() - 1]; // Mon=1 -> idx 0
      if (!dayName) continue; // skip weekends
      const dateStr = d.toISOString().split('T')[0];
      slots.forEach(slot => {
        if (slot.day === dayName) {
          const freeTeachers = findFreeTeachers(dayName, slot.period, teacherId);
          affectedSlots.push({
            date: dateStr,
            day: dayName,
            period: slot.period,
            class: slot.class,
            time: PERIOD_TIMES[slot.period],
            freeTeachers,
          });
        }
      });
    }
    return affectedSlots;
  }, [timetable, findFreeTeachers]);

  // Apply for leave - auto generate substitute requests
  const applyLeave = useCallback((teacherId, fromDate, toDate, reason) => {
    const teacher = staff.find(t => t.id === teacherId);
    if (!teacher) return;

    const affectedSlots = getTeacherSlots(teacherId, fromDate, toDate);
    const substituteRequests = affectedSlots.map(slot => ({
      date: slot.date,
      day: slot.day,
      period: slot.period,
      class: slot.class,
      time: slot.time,
      freeTeachers: slot.freeTeachers,
      assignedTeacherId: slot.freeTeachers.length > 0 ? slot.freeTeachers[0].id : null,
      subStatus: "pending",
    }));

    const newRequest = {
      id: Date.now(),
      teacherId,
      teacherName: teacher.name,
      fromDate,
      toDate,
      reason,
      status: "pending",
      substituteRequests,
      createdAt: new Date().toISOString().split('T')[0],
    };

    setLeaveRequests(prev => [...prev, newRequest]);

    // Auto-notify free teachers
    substituteRequests.forEach(sub => {
      if (sub.assignedTeacherId) {
        const subTeacher = staff.find(t => t.id === sub.assignedTeacherId);
        addNotification({
          type: "substitute_request",
          message: `${teacher.name} is on leave on ${sub.date}. You are free during Period ${sub.period} (${sub.time}). Please cover ${sub.class}.`,
          toTeacherId: sub.assignedTeacherId,
          toTeacherName: subTeacher?.name,
          leaveRequestId: newRequest.id,
          date: sub.date,
        });
      }
    });

    addNotification({
      type: "leave_applied",
      message: `New leave request from ${teacher.name} (${fromDate} to ${toDate})`,
      toTeacherId: 0, // admin
      leaveRequestId: newRequest.id,
      date: new Date().toISOString().split('T')[0],
    });

    return newRequest;
  }, [staff, getTeacherSlots]);

  // Admin approve/reject leave
  const updateLeaveStatus = useCallback((requestId, status) => {
    setLeaveRequests(prev => prev.map(req => {
      if (req.id !== requestId) return req;
      const updated = { ...req, status };
      // notify teacher
      const teacher = staff.find(t => t.id === req.teacherId);
      addNotification({
        type: status === "approved" ? "leave_approved" : "leave_rejected",
        message: `Your leave request (${req.fromDate} to ${req.toDate}) has been ${status}.`,
        toTeacherId: req.teacherId,
        toTeacherName: teacher?.name,
        leaveRequestId: requestId,
        date: new Date().toISOString().split('T')[0],
      });
      return updated;
    }));
  }, [staff]);

  // Update substitute assignment
  const updateSubstitute = useCallback((requestId, slotIndex, teacherId) => {
    setLeaveRequests(prev => prev.map(req => {
      if (req.id !== requestId) return req;
      const updated = [...req.substituteRequests];
      updated[slotIndex] = { ...updated[slotIndex], assignedTeacherId: teacherId };
      return { ...req, substituteRequests: updated };
    }));
  }, []);
  // Teacher accepts substitute request
const acceptSubstitute = useCallback((requestId, slotIndex, teacherId) => {
  setLeaveRequests(prev =>
    prev.map(req => {
      if (req.id !== requestId) return req;

      const updatedSubs = [...req.substituteRequests];

      updatedSubs[slotIndex] = {
        ...updatedSubs[slotIndex],
        assignedTeacherId: teacherId,
        subStatus: "accepted"
      };

      const acceptedTeacher = staff.find(t => t.id === teacherId);

      addNotification({
        type: "substitute_accepted",
        message: `${acceptedTeacher?.name} accepted to cover your class on ${updatedSubs[slotIndex].date} (Period ${updatedSubs[slotIndex].period}).`,
        toTeacherId: req.teacherId,
        toTeacherName: staff.find(t => t.id === req.teacherId)?.name,
        leaveRequestId: requestId,
        date: new Date().toISOString().split('T')[0],
      });

      return { ...req, substituteRequests: updatedSubs };
    })
  );
}, [staff]);

  // Add timetable entry for a staff
  const addTimetableEntry = useCallback((teacherId, entry) => {
    setTimetable(prev => ({
      ...prev,
      [teacherId]: [...(prev[teacherId] || []), entry],
    }));
  }, []);

  // Remove timetable entry
  const removeTimetableEntry = useCallback((teacherId, index) => {
    setTimetable(prev => ({
      ...prev,
      [teacherId]: prev[teacherId].filter((_, i) => i !== index),
    }));
  }, []);

  // Add staff member
  const addStaffMember = useCallback((member) => {
    const newMember = { ...member, id: Date.now(), role: "teacher" };
    setStaff(prev => [...prev, newMember]);
    setTimetable(prev => ({ ...prev, [newMember.id]: [] }));
    return newMember;
  }, []);

  const addNotification = (notif) => {
    setNotifications(prev => [{ ...notif, id: Date.now(), read: false }, ...prev]);
  };

  const markNotificationRead = useCallback((id) => {
    setNotifications(prev => prev.map(n => n.id === id ? { ...n, read: true } : n));
  }, []);

  return (
    <AppContext.Provider value={{
      staff, setStaff,
      timetable, setTimetable,
      leaveRequests, setLeaveRequests,
      notifications, markNotificationRead,
      currentUser, setCurrentUser,
      applyLeave,
      updateLeaveStatus,
      updateSubstitute,
      acceptSubstitute,
      addTimetableEntry,
      removeTimetableEntry,
      addStaffMember,
      getTeacherSlots,
      findFreeTeachers,
    }}>
      {children}
    </AppContext.Provider>
  );
}

export const useApp = () => useContext(AppContext);
